import { Component, h, Prop, Element } from '@stencil/core';

@Component({
  tag: 'wdpr-tile-cell',
  shadow: true,
})
export class WdprTileCell {
  @Element() el: HTMLWdprTileCellElement;

  @Prop({ reflect: true, mutable: true }) cellColumns: number = 1;

  render() {
    return (
      <div
        class={cellClass}
        style={{ gridTemplateColumns: `repeat(${this.cellColumns}, 1fr)` }}
      >
        <slot></slot>
      </div>
    );
  }
}

const cellClass = "grid gap-100";
